def find_peak_element(nums):
    n = len(nums)

    if n == 0:
        return None
    if n == 1:
        return nums[0]

    low = 0
    high = n - 1

    while low <= high:
        mid = low + (high - low) // 2

        is_left_greater_or_equal = (mid == 0 or nums[mid] >= nums[mid - 1])
        is_right_greater_or_equal = (mid == n - 1 or nums[mid] >= nums[mid + 1])

        if is_left_greater_or_equal and is_right_greater_or_equal:
            return nums[mid]
        elif mid > 0 and nums[mid] < nums[mid - 1]:
            high = mid - 1
        else:
            low = mid + 1

    return None
